import React, { useEffect, useState } from "react";
import { io } from "socket.io-client";
import waveAgent from "../assets/waveAgent.png";   // adjust path if needed
import "./chatBot.css";

const socket = io("http://localhost:3002");

const ChatBot = () => {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [isOpen, setIsOpen] = useState(false);

  useEffect(() => {
    socket.on("aiMessage", (msg) => {
      setMessages((prev) => [...prev, { type: "ai", text: msg }]);
    });

    return () => socket.off("aiMessage");
  }, []);

  const sendMessage = () => {
    if (!input.trim()) return;

    socket.emit("userMessage", input);

    setMessages((prev) => [...prev, { type: "user", text: input }]);
    setInput("");
  };

  return (
    <>
      {/* 🔥 Floating Image Icon */}
      <img
        src={waveAgent}
        alt="Wave Agent"
        className="chat-icon-img"
        onClick={() => setIsOpen(!isOpen)}
      />

      {/* 🔥 Chat Window */}
      {isOpen && (
        <div className="chat-window">
          <div className="chat-header">
            Wave Agent
            <span className="close-btn" onClick={() => setIsOpen(false)}>
              ✖
            </span>
          </div>

          <div className="chat-body">
            {messages.map((msg, i) => (
              <div key={i} className={`msg ${msg.type}`}>
                {msg.text}
              </div>
            ))}
          </div>

          <div className="chat-input">
            <input
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="Ask about portfolio or buy stock..."
              onKeyDown={(e) => e.key === "Enter" && sendMessage()}
            />
            <button onClick={sendMessage}>Send</button>
          </div>
        </div>
      )}
    </>
  );
};

export default ChatBot;
